function loadStorageData() {
    // 调用之前写的获取列表接口 (因为它包含 total 和 used 信息)
    fetch('/photo/list')
        .then(res => res.json())
        .then(data => {
            // 更新存储条 (两个页面都有这个元素，所以可以共用)
            updateStorageUI(data.total, data.used);

            // 如果页面上有文件列表 (仅 photo.html 有)，则更新列表
