// ============================================
// 新增：通用文件上传 (不限制 GIF，不限制尺寸)
// ============================================
window.uploadGenericFile = function() {
    const fileInput = document.getElementById('genericFile');
    // 检查是否有文件
    if (!fileInput || !fileInput.files[0]) {
        alert("Please select a file first.");
        return;
    }

    const file = fileInput.files[0];
    const btn = document.querySelector("button[onclick='uploadGenericFile()']");
    const originalText = btn.innerText;

    // 确认提示
    if (!confirm(`Upload "${file.name}" (${formatSize(file.size)}) to root directory?`)) {
        return;
    }

    // 禁用按钮防止重复点击
    btn.disabled = true;
    btn.innerText = "Uploading...";

    const formData = new FormData();
    // 关键：这里的 filename 会被 C++ 端的 upload.filename 接收
    formData.append("file", file, file.name);

    fetch("/upload", {
        method: "POST",
        body: formData
    })
    .then(res => {
        if (res.ok) {
            alert("Upload Success: " + file.name);
            fileInput.value = ''; // 清空选择框
            // 如果你上传的是 javascript.js 或 index.html，建议刷新页面
            if (file.name === 'index.html' || file.name === 'javascript.js' || file.name === 'style.css') {
                if(confirm("System file updated. Refresh page now?")) {
                    location.reload();
                }
            }
        } else {
            alert("Server Error: " + res.status);
        }
    })
    .catch(err => {
        console.error(err);
        alert("Upload Failed (Network Error)");
    })
    .finally(() => {
        // 恢复按钮状态
        btn.disabled = false;
        btn.innerText = originalText;
    });
};
